# Initialize database
def init_db():
    conn = sqlite3.connect('model_data.db')
    c = conn.cursor()
    c.execute('''
        CREATE TABLE IF NOT EXISTS training_data (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            filename TEXT,
            content_hash TEXT,
            timestamp TEXT,
            user_id TEXT,
            label TEXT,
            status TEXT DEFAULT 'pending'
        )
    ''')
    conn.commit()
    conn.close()

# Initialize database
init_db()

# Secure file upload validation
def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

# Secure hash function for data integrity
def calculate_hash(data):
    return hashlib.sha256(data).hexdigest()

# Secure data loading and validation
def load_csv_data(file_path):
    try:
        df = pd.read_csv(file_path)
        # Validate CSV structure
        if df.empty:
            raise ValueError("CSV file is empty")
        if len(df.columns) < 2:
            raise ValueError("CSV must have at least 2 columns")
        return df
    except Exception as e:
        raise ValueError(f"Invalid CSV file: {str(e)}")

# Secure model training function
def train_model(data, labels):
    # Encode labels
    label_encoder = LabelEncoder()
    encoded_labels = label_encoder.fit_transform(labels)
    
    # Create model
    model = tf.keras.Sequential([
        tf.keras.layers.Flatten(input_shape=(28, 28)),
        tf.keras.layers.Dense(128, activation='relu'),
        tf.keras.layers.Dropout(0.2),
        tf.keras.layers.Dense(len(np.unique(encoded_labels)), activation='softmax')
    ])
    
    model.compile(optimizer='adam',
                  loss='sparse_categorical_crossentropy',
                  metrics=['accuracy'])
    
    # Train model
    model.fit(data, encoded_labels, epochs=5, validation_split=0.2)
    
    return model, label_encoder

# Secure data ingestion pipeline
@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        
        # Validate file integrity
        with open(file_path, 'rb') as f:
            file_content = f.read()
        
        content_hash = calculate_hash(file_content)
        
        # Store in database
        conn = sqlite3.connect('model_data.db')
        c = conn.cursor()
        c.execute('''
            INSERT INTO training_data (filename, content_hash, timestamp, user_id, status)
            VALUES (?, ?, ?, ?, ?)
        ''', (filename, content_hash, datetime.now().isoformat(), request.remote_addr, 'pending'))
        conn.commit()
        conn.close()
        
        return jsonify({
            'message': 'File uploaded successfully',
            'filename': filename,
            'hash': content_hash
        }), 200
    
    return jsonify({'error': 'Invalid file type'}), 400

# Secure model retraining endpoint
@app.route('/retrain', methods=['POST'])
def retrain_model():
    try:
        # Load pending training data
        conn = sqlite3.connect('model_data.db')
        c = conn.cursor()
        c.execute("SELECT filename, content_hash FROM training_data WHERE status = 'pending'")
        pending_data = c.fetchall()
        conn.close()
        
        if not pending_data:
            return jsonify({'message': 'No pending data for training'}), 200
        
        # Process training data
        all_data = []
        all_labels = []
        
        for filename, _ in pending_data:
            file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            if filename.endswith('.csv'):
                df = load_csv_data(file_path)
                # Assuming first column is labels and rest are features
                labels = df.iloc[:, 0].values
                features = df.iloc[:, 1:].values
                all_data.extend(features)
                all_labels.extend(labels)
        
        if not all_data:
            return jsonify({'error': 'No valid training data found'}), 400
        
        # Convert to numpy arrays
        data = np.array(all_data)
        labels = np.array(all_labels)
        
        # Train model
        model, label_encoder = train_model(data, labels)
        
        # Save model
        model.save('trained_model.h5')
        
        # Update database status
        conn = sqlite3.connect('model_data.db')
        c = conn.cursor()
        c.execute("UPDATE training_data SET status = 'processed' WHERE status = 'pending'")
        conn.commit()
        conn.close()
        
        return jsonify({'message': 'Model retrained successfully'}), 200
        
    except Exception as e:
        logging.error(f"Retraining error: {str(e)}")
        return jsonify({'error': 'Model retraining failed'}), 500

